Set-StrictMode -Version 2.0
function Test-GodModeInjectionText { param([string]$Text,[string]$Project='.') $hits=@(); foreach($p in @('ignore previous instructions','system prompt','you are now','override AGENTS.md','(^|[\\/])\.\.([\\/]|$)','[A-Za-z0-9+/]{4000,}')){ if($Text -match $p){ $hits+=$p } }; @{ok=($hits.Count -eq 0);hits=$hits} }
function Test-GodModeResultSafety { param($Result,[string]$Project='.') $errors=@(); foreach($p in @('summary','deity_name','deity_form')){ if($Result.PSObject.Properties.Name -contains $p){ $s=Test-GodModeInjectionText ([string]$Result.$p) $Project; if(-not $s.ok){ $errors += "injection:$p" } } }; foreach($f in @($Result.files_touched)){ if($f -match '(^|[\\/])\.\.([\\/]|$)'){ $errors += "path_traversal:$f" } }; @{ok=($errors.Count -eq 0);errors=$errors} }
